using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayChargeAsyncTests
{
    private PaymentGateway _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCardTokenAndPositiveAmount_ReturnsSuccessfulResult()
    {
        // Arrange
        var cardToken = "tok_valid_visa_4242";
        var amount = 49.99m;

        // Act
        var result = await _sut.ChargeAsync(cardToken, amount);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCardTokenAndLargeAmount_ReturnsSuccessfulResult()
    {
        // Arrange
        var cardToken = "tok_valid_mastercard";
        var amount = 9999.99m;

        // Act
        var result = await _sut.ChargeAsync(cardToken, amount);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCardTokenAndSmallAmount_ReturnsSuccessfulResult()
    {
        // Arrange
        var cardToken = "tok_valid_amex";
        var amount = 0.01m;

        // Act
        var result = await _sut.ChargeAsync(cardToken, amount);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        // Arrange
        var cardToken = "tok_valid_visa_4242";
        var amount = 0m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        // Arrange
        var cardToken = "tok_valid_visa_4242";
        var amount = -10.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Slightly negative amount")]
    [DataRow(-100.00, DisplayName = "Large negative amount")]
    [DataRow(-9999.99, DisplayName = "Very large negative amount")]
    public async Task ChargeAsync_VariousNegativeAmounts_ThrowsArgumentException(double amountDouble)
    {
        // Arrange
        var cardToken = "tok_valid_visa_4242";
        var amount = (decimal)amountDouble;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_NullCardToken_ThrowsArgumentNullException()
    {
        // Arrange
        string cardToken = null!;
        var amount = 25.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyCardToken_ThrowsArgumentException()
    {
        // Arrange
        var cardToken = string.Empty;
        var amount = 25.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceCardToken_ThrowsArgumentException()
    {
        // Arrange
        var cardToken = "   ";
        var amount = 25.00m;

        // Act & Assert
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(cardToken, amount));
    }

    [TestMethod]
    public async Task ChargeAsync_SuccessfulCharge_ReturnsUniqueChargeIds()
    {
        // Arrange
        var cardToken = "tok_valid_visa_4242";
        var amount = 10.00m;

        // Act
        var result1 = await _sut.ChargeAsync(cardToken, amount);
        var result2 = await _sut.ChargeAsync(cardToken, amount);

        // Assert
        Assert.IsNotNull(result1);
        Assert.IsNotNull(result2);
        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId,
            "Each charge should produce a unique ChargeId.");
    }
}

[TestClass]
public sealed class PaymentGatewayRefundAsyncTests
