        // Arrange
        var chargeId = "   ";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ThrowsInvalidOperationException()
    {
        // Arrange
        var chargeId = "ch_nonexistent_000";

        // Act & Assert
        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _sut.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_SuccessfulRefund_ReturnsUniqueRefundIds()
    {
        // Arrange
        var chargeId1 = "ch_valid_111";
        var chargeId2 = "ch_valid_222";

        // Act
        var result1 = await _sut.RefundAsync(chargeId1);
        var result2 = await _sut.RefundAsync(chargeId2);

        // Assert
        Assert.IsNotNull(result1);
        Assert.IsNotNull(result2);
        Assert.AreNotEqual(result1.RefundId, result2.RefundId,
            "Each refund should produce a unique RefundId.");
    }
}

